package com.maum.backend.service

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.entity.user.UserEntity
import com.maum.backend.repository.follow.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

@Service
class UserService(
    private val userRepository: UserRepository,
    private val followRepository: FollowRepository,
) {

    @Transactional
    fun follow(followerId: String, followeeId: String) {
        if (followerId == followeeId) {
            throw IllegalArgumentException("자기 자신을 팔로우할 수 없습니다.")
        }

        userRepository.findById(followeeId).orElseThrow {
            NoSuchElementException("존재하지 않는 사용자입니다. followeeId=$followeeId")
        }

        if (followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)) {
            throw IllegalStateException("이미 팔로우한 사용자입니다.")
        }

        followRepository.save(
            FollowEntity(
                followerId = followerId,
                followeeId = followeeId,
            )
        )
    }

    @Transactional
    fun unfollow(followerId: String, followeeId: String) {
        if (!followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)) {
            throw IllegalStateException("팔로우 관계가 존재하지 않습니다.")
        }
        followRepository.deleteByFollowerIdAndFolloweeId(followerId, followeeId)
    }

    @Transactional(readOnly = true)
    fun getFollowings(userId: String): List<FollowEntity> {
        return followRepository.findByFollowerId(userId)
    }

    @Transactional(readOnly = true)
    fun getFollowers(userId: String): List<FollowEntity> {
        return followRepository.findByFolloweeId(userId)
    }
}
```

