package com.maum.backend.service

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.entity.user.UserEntity
import com.maum.backend.repository.follow.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.never
import org.mockito.Mockito.verify
import org.mockito.Mockito.`when`
import org.mockito.junit.jupiter.MockitoExtension
import org.mockito.kotlin.any
import java.util.Optional

@ExtendWith(MockitoExtension::class)
class UserServiceTest {

    @Mock
    private lateinit var userRepository: UserRepository

    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var userService: UserService

    // ── follow ──────────────────────────────────────────────────────────────

    @Test
    fun `should follow successfully when valid follower and followee`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        val followee = UserEntity(id = followeeId, nickname = "userB")

        `when`(userRepository.findById(followeeId)).thenReturn(Optional.of(followee))
        `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(false)

        // when
        userService.follow(followerId, followeeId)

        // then
        verify(followRepository).save(
            any<FollowEntity>()
        )
    }

    @Test
    fun `should throw when follower tries to follow themselves`() {
        // given
        val userId = "user-A"

        // when & then
        val exception = assertThrows<IllegalArgumentException> {
            userService.follow(userId, userId)
        }
        assertThat(exception.message).contains("자기 자신을 팔로우할 수 없습니다")

        verify(followRepository, never()).save(any())
        verify(userRepository, never()).findById(any())
    }

    @Test
    fun `should throw when followee does not exist`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-not-found"

        `when`(userRepository.findById(followeeId)).thenReturn(Optional.empty())

        // when & then
        val exception = assertThrows<NoSuchElementException> {
            userService.follow(followerId, followeeId)
        }
        assertThat(exception.message).contains(followeeId)

        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should throw when already following the same user`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        val followee = UserEntity(id = followeeId, nickname = "userB")

        `when`(userRepository.findById(followeeId)).thenReturn(Optional.of(followee))
        `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(true)

        // when & then
        val exception = assertThrows<IllegalStateException> {
            userService.follow(followerId, followeeId)
        }
        assertThat(exception.message).contains("이미 팔로우한 사용자입니다")

        verify(followRepository, never()).save(any())
    }

    // ── unfollow ─────────────────────────────────────────────────────────────

    @Test
    fun `should unfollow successfully when follow relationship exists`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"

        `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(true)

        // when
        userService.unfollow(followerId, followeeId)

        // then
        verify(followRepository).deleteByFollowerIdAndFolloweeId(followerId, followeeId)
    }

    @Test
    fun `should throw when unfollow target is not followed`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"

        `when`(followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(false)

        // when & then
        val exception = assertThrows<IllegalStateException> {
            userService.unfollow(followerId, followeeId)
        }
        assertThat(exception.message).contains("팔로우 관계가 존재하지 않습니다")

        verify(followRepository, never()).deleteByFollowerIdAndFolloweeId(any(), any())
    }

    // ── getFollowings ────────────────────────────────────────────────────────

    @Test
    fun `should return followings list for given userId`() {
        // given
        val userId = "user-A"
        val followings = listOf(
            FollowEntity(id = "f1", followerId = userId, followeeId = "user-B"),
            FollowEntity(id = "f2", followerId = userId, followeeId = "user-C"),
        )

        `when`(followRepository.findByFollowerId(userId)).thenReturn(followings)

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result.map { it.followeeId }).containsExactlyInAnyOrder("user-B", "user-C")
        verify(followRepository).findByFollowerId(userId)
    }

    @Test
    fun `should return empty list when no followings exist`() {
        // given
        val userId = "user-lonely"

        `when`(followRepository.findByFollowerId(userId)).thenReturn(emptyList())

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).isEmpty()
    }

    // ── getFollowers ─────────────────────────────────────────────────────────

    @Test
    fun `should return followers list for given userId`() {
        // given
        val userId = "user-B"
        val followers = listOf(
            FollowEntity(id = "f1", followerId = "user-A", followeeId = userId),
            FollowEntity(id = "f2", followerId = "user-C", followeeId = userId),
            FollowEntity(id = "f3", followerId = "user-D", followeeId = userId),
        )

        `when`(followRepository.findByFolloweeId(userId)).thenReturn(followers)

        // when
        val result = userService.getFollowers(userId)

        // then
        assertThat(result).hasSize(3)
        assertThat(result.map { it.followerId })
            .containsExactlyInAnyOrder("user-A", "user-C", "user-D")
        verify(followRepository).findByFolloweeId(userId)
    }

    @Test
    fun `should return empty list when no followers exist`() {
        // given
        val userId = "user-new"

        `when`(followRepository.findByFolloweeId(userId)).thenReturn(emptyList())

        // when
        val result = userService.getFollowers(userId)

        // then
        assertThat(result).isEmpty()
    }
}
